func (c *current) onCase1(operand, cs, last any) (any, error) {
	var expr Node
	if operand != nil {
		expr = operand.(Node)
	} else {
		// Desugar to case (true) when operand is omitted
		expr = &Boolean{
			Value: true,
			Loc:   c.Loc(),
		}
	}
	return &Case{
		Expr:      expr,
		NoOperand: operand == nil,
		Clauses:   sliceOfAppend[*CaseClause](cs, last),
		Loc:       c.Loc(),
	}, nil
}

